  // allocation / deallocation\n        void drain();\n        void *alloc(unsigned int size);\n        void *zero_alloc(unsigned int size);\n        \n        // Destructor\n        ~Alloc();\n    protected:\n        std::vector<void *> memory;\n    };\n    \n    // implementaion\n    void Alloc::drain() {\n        std::cout << \"Draining pool of \" << memory.size() << \" releasing pointers..\\n\";\n        if(memory.empty()) return;\n        for(auto i = memory.begin(); i != memory.end(); ++i) {\n            std::cout << \"Releasing Pointer address: 0x\" << std::hex << (unsigned long)*i << \"\\n\";\n            free(*i);\n        }\n        memory.erase(memory.begin(), memory.end());\n    }\n    \n    void *Alloc::alloc(unsigned int size) {\n        void *buffer = malloc(size);\n        memory.push_back(buffer);\n        return buffer;\n    }\n    \n    void *Alloc::zero_alloc(unsigned int size) {\n        void *buffer = calloc(1, size);\n        memory.push_back(buffer);\n        return buffer;\n    }\n    \n    \n    Alloc::~Alloc() {\n        drain();\n    }\n}\n\n\n#endif\n"}, {"path": "printdir/Makefile", "name": "Makefile", "directory": "printdir", "extension": "Makefile", "lineCount": 10, "summary": "This file appears to be a support artifact for printdir, included in the C++11 examples set.", "demonstrates": ["Topic area: printdir.", "Use this file as a focused reference for the concept shown by its directory and symbol names."], "features": [], "includes": [], "classes": [], "functions": [], "complexity": "Low", "lineNotes": [], "code": "PRINTDIR_SOURCE=printdir.cpp\nPRINTDIR_OUTPUT=printdir-test\nCFLAGS=-std=c++11\n\nall: $(PRINTDIR_OUTPUT)\n\n$(PRINTDIR_OUTPUT): $(PRINTDIR_SOURCE)\n\t$(CXX) $(CFLAGS) $(PRINTDIR_SOURCE) -o $(PRINTDIR_OUTPUT)\nclean:\n\trm -f printdir-test\n"}, {"path": "printdir/printdir.cpp", "name": "printdir.cpp", "directory": "printdir", "extension": ".cpp", "lineCount": 84, "summary": "This printdir example includes 1 type declarati